import os

def w(relpath, content):
    path = os.path.join('MiniHigherHomotopy', relpath)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(content)
    print(f'{relpath}: {len(content.splitlines())} lines')

