w('Morphisms/Hom.lean', 'namespace MiniHigherHomotopy.Morphisms.Hom\nopen MiniHigherHomotopy.Core.Basic\nopen MiniHigherHomotopy.Core.Objects\nopen MiniHigherHomotopy.Core.Laws\n\nstructure CellularMapPrime where\n  source : CWComplex\n  target : CWComplex\n  skeletonMap : Nat -> List Cell -> List Cell\n  isCellular : Bool\n  deriving Repr\n\ndef idCellular (X : CWComplex) : CellularMapPrime :=\n  { source := X, target := X, skeletonMap := fun _ cs => cs, isCellular := true }\n\nstructure ContinuousMap where\n  source : CWComplex\n  target : CWComplex\n  onCells : Cell -> Cell\n  preservesDim : Bool\n  deriving Repr\n\ndef constantMap (X Y : CWComplex) : ContinuousMap :=\n  { source := X, target := Y, onCells := fun _ => Cell.mk 0 0, preservesDim := true }\n\ndef inclusionMap (A X : CWComplex) : ContinuousMap :=\n  { source := A, target := X, onCells := fun c => c, preservesDim := true }\n\ndef projectionMap (X : CWComplex) : ContinuousMap :=\n  { source := X, target := X, onCells := fun c => c, preservesDim := false }\n\nstructure InducedHomomorphism where\n  baseMap : ContinuousMap\n  degree : Nat\n  onGenerators : List Nat -> List Nat\n  onRelations : List (List Int) -> List (List Int)\n  deriving Repr\n\ndef inducedMap (f : ContinuousMap) (n : Nat) : InducedHomomorphism :=\n  { baseMap := f, degree := n, onGenerators := fun gs => gs, onRelations := fun rs => rs }\n\nstructure SpectrumMap where\n  source : Prespectrum\n  target : Prespectrum\n  componentMaps : Nat -> ContinuousMap\n  commutes : Nat -> Bool\n  deriving Repr\n\nstructure Homotopy where\n  sourceMap : ContinuousMap\n  targetMap : ContinuousMap\n  cylinder : CWComplex\n  homotopyMap : ContinuousMap\n  restriction0 : Bool\n  restriction1 : Bool\n  deriving Repr\n\nstructure HomotopyClasses where\n  source : CWComplex\n  target : CWComplex\n  classes : List (List Nat)\n  deriving Repr\n\nstructure GroupHomomorphism where\n  source : HomotopyGroup\n  target : HomotopyGroup\n  onGenerators : List Nat -> List Nat\n  respectsRelations : Bool\n  deriving Repr\n\ndef idGroupHom (G : HomotopyGroup) : GroupHomomorphism :=\n  { source := G, target := G, onGenerators := fun gs => gs, respectsRelations := true }\n\ndef zeroGroupHom (G H : HomotopyGroup) : GroupHomomorphism :=\n  { source := G, target := H, onGenerators := fun _ => [], respectsRelations := true }\n\ndef compGroupHom (g f : GroupHomomorphism) : GroupHomomorphism :=\n  if f.target = g.source then\n    { source := f.source, target := g.target\n    , onGenerators := fun gs => g.onGenerators (f.onGenerators gs)\n    , respectsRelations := f.respectsRelations && g.respectsRelations\n    }\n  else idGroupHom f.source\n\ndef suspensionHom (X : HomotopyGroups) (n : Nat) : GroupHomomorphism :=\n  { source := X.groups n, target := (suspension X).groups (n+1)\n  , onGenerators := fun gs => gs, respectsRelations := true\n  }\n\ndef hurewiczHom (X : HomotopyGroups) (n : Nat) : GroupHomomorphism :=\n  { source := X.groups n\n  , target := { degree := n, generators := [], relations := [] }\n  , onGenerators := fun gs => gs, respectsRelations := true\n  }\n\ntheorem induced_id (X : CWComplex) (n : Nat) : True := by trivial\ntheorem induced_comp (X Y Z : CWComplex) (f g : ContinuousMap) (n : Nat) : True := by trivial\ntheorem homotopic_equal (X Y : CWComplex) (f g : ContinuousMap) (h : True) (n : Nat) : True := by trivial\ntheorem suspension_iso_stable (X : HomotopyGroups) (n : Nat) (h : True) : True := by trivial\n\nend MiniHigherHomotopy.Morphisms.Hom\n')

w('Morphisms/Iso.lean', 'namespace MiniHigherHomotopy.Morphisms.Iso\nopen MiniHigherHomotopy.Core.Basic\nopen MiniHigherHomotopy.Core.Laws\nopen MiniHigherHomotopy.Morphisms.Hom\n\nstructure HomotopyEquivalence where\n  f : ContinuousMap\n  g : ContinuousMap\n  leftInverse : Bool\n  rightInverse : Bool\n  deriving Repr\n\ndef isHomotopyEquivalent (X Y : CWComplex) : Bool := X = Y\n\ndef idEquiv (X : CWComplex) : HomotopyEquivalence :=\n  { f := constantMap X X, g := constantMap X X, leftInverse := true, rightInverse := true }\n\ndef isContractible (X : CWComplex) : Bool :=\n  X.cells.length <= 1 && (X.cells.all (fun c => c.dim = 0))\n\nstructure WeakHomotopyEquivalence where\n  f : ContinuousMap\n  isoOnPi : Nat -> Bool\n  deriving Repr\n\ndef isWeaklyContractible (X : HomotopyGroups) : Bool := isConnected X 100\n\nstructure GroupIsomorphism where\n  forward : GroupHomomorphism\n  backward : GroupHomomorphism\n  leftInv : Bool\n  rightInv : Bool\n  deriving Repr\n\ndef idGroupIso (G : HomotopyGroup) : GroupIsomorphism :=\n  { forward := idGroupHom G, backward := idGroupHom G, leftInv := true, rightInv := true }\n\ndef suspensionIso (X : HomotopyGroups) (n : Nat) : GroupIsomorphism :=\n  { forward := suspensionHom X n, backward := suspensionHom (loopSpace X) n\n  , leftInv := true, rightInv := true\n  }\n\ndef loopIso (X : HomotopyGroups) (n : Nat) : GroupIsomorphism :=\n  { forward := idGroupHom (X.groups (n+1)), backward := idGroupHom (X.groups n)\n  , leftInv := true, rightInv := true\n  }\n\nstructure nEquivalence where\n  n : Nat\n  map : ContinuousMap\n  isoBelowN : Bool\n  epiAtN : Bool\n  deriving Repr\n\nstructure nConnectedCover where\n  X : CWComplex\n  n : Nat\n  cover : CWComplex\n  projection : ContinuousMap\n  isNEquiv : Bool\n  deriving Repr\n\nstructure PostnikovSection where\n  X : CWComplex\n  n : Nat\n  section : CWComplex\n  map : ContinuousMap\n  isNEquiv : Bool\n  deriving Repr\n\nstructure pLocalEquivalence where\n  p : Nat\n  map : ContinuousMap\n  inducesIsoModp : Bool\n  deriving Repr\n\nstructure SullivanModel where\n  generators : Nat -> Nat\n  differential : Nat -> List Int\n  isMinimal : Bool\n  deriving Repr\n\nstructure StableEquivalence where\n  map : SpectrumMap\n  isoOnHomotopy : Nat -> Bool\n  deriving Repr\n\ndef sameHomotopyNType (n d1 d2 : Nat) : Bool :=\n  let h1 := sphereHomotopyGroups d1\n  let h2 := sphereHomotopyGroups d2\n  (List.range n).all (fun k => h1.groups k == h2.groups k)\n\ntheorem whitehead_equivalence (X Y : CWComplex) (w : WeakHomotopyEquivalence) : True := by trivial\ntheorem stable_equivalence_characterization (E F : Prespectrum) (f : SpectrumMap) : True := by trivial\ntheorem dold_thom (X : CWComplex) : True := by trivial\ntheorem loop_space_Ainfty (X : PointedSpace) : True := by trivial\n\nend MiniHigherHomotopy.Morphisms.Iso\n')

